// Limita a los N más recientes actualizados para acotar coste.
// Cambia este número si quieres más profundidad.
const MAX = 250;
const tickets = $input.all().map(i => i.json).filter(t => t && t.id);
tickets.sort((a,b) => new Date(b.updated_at) - new Date(a.updated_at));
const limited = tickets.slice(0, MAX);
return limited.map(t => ({ json: t }));

// Cruza cada ticket con su último comentario y filtra los que tienen
// como último autor al SOLICITANTE (requester_id).
const tickets = $('Limitar a 250').all().map(i => i.json);
const commentResps = $input.all().map(i => i.json);

const matches = [];
const checked = [];
let skipped = 0;

for (let i = 0; i < tickets.length; i++) {
  const t = tickets[i];
  const cr = commentResps[i] || {};
  // Zendesk devuelve sort_order=desc → comments[0] es el más reciente
  const comments = Array.isArray(cr.comments) ? cr.comments : [];
  if (comments.length === 0) { skipped++; continue; }
  const last = comments[0];
  const ageDays = t.created_at ? Math.floor((Date.now() - new Date(t.created_at).getTime()) / 86400000) : null;
  const sinceLastDays = last.created_at ? Math.floor((Date.now() - new Date(last.created_at).getTime()) / 86400000) : null;
  const item = {
    ticket_id: t.id,
    subject: t.subject,
    status: t.status,
    age_days: ageDays,
    days_since_last_comment: sinceLastDays,
    last_comment_at: last.created_at,
    last_author_id: last.author_id,
    requester_id: t.requester_id,
    is_public: last.public === true,
    url: `https://soporteyurest.zendesk.com/agent/tickets/${t.id}`
  };
  checked.push(item);
  if (last.author_id === t.requester_id) {
    matches.push(item);
  }
}

matches.sort((a,b) => (a.days_since_last_comment ?? 999) - (b.days_since_last_comment ?? 999));

return [{ json: {
  generated_at: new Date().toISOString(),
  tickets_open_total: tickets.length,
  tickets_checked: checked.length,
  tickets_skipped_no_comments: skipped,
  needs_agent_reply_count: matches.length,
  needs_agent_reply_ids_csv: matches.map(m => m.ticket_id).join(','),
  needs_agent_reply: matches
} }];
